    "source_fingerprint": "{\"title\":\"Grammatica - Interjecties\",\"order_index\":4,\"content\":{\"type\":\"grammar\",\"categories\":[{\"rules\":[\"Het Indonesisch heeft veel korte woordjes (interjecties) die voornamelijk in de spreektaal voorkomen.\",\"Ze geven uiting aan speciale gevoelens (vergelijk in het Nederlands: goh, ooh, eh, he, nou ja).\",\"Ze verlenen nadruk aan het woord waar ze bij staan (mahal dong!).\",\"Ze markeren grenzen tussen woordgroepen, vaak met een korte pauze, en dragen bij aan het staccato-effect van gesproken Indonesisch.\"],\"title\":\"Interjecties\"},{\"table\":[[\"ya\",\"positief / bevestigend\"],[\"wah\",\"milde verbazing\"],[\"nah\",\"nadruk\"],[\"dong\",\"nadruk / verzachtend bij gebiedende wijs\"],[\"kok\",\"verbazing\"],[\"deh\",\"afsluitend\"],[\"lho\",\"verbazing\"],[\"nih\",\"milde verbazing\"],[\"sih\",\"nadruk\"]],\"title\":\"Overzicht interjecties\",\"examples\":[{\"dutch\":\"Het is duur, hoor!\",\"indonesian\":\"Mahal dong!\"},{\"dutch\":\"Kijk dan!\",\"indonesian\":\"Lihat dong!\"},{\"dutch\":\"De prijs is warempel Rp 46.500.\",\"indonesian\":\"Harganya, kok, Rp 46.500.\"},{\"dutch\":\"Wauw, ik ben blij!\",\"indonesian\":\"Wah, saya senang!\"}]}],\"grammar_topics\":[\"Interjecties\",\"Trappen van vergelijking\"]}}"
